506: // processNextWorkItem works on one entry from the work queue.
507: // Only invoke this in the one and only worker goroutine.
508: func (cfgCtlr *configController) processNextWorkItem() bool {
509: 	obj, shutdown := cfgCtlr.configQueue.Get()
510: 	if shutdown {
511: 		return false
512: 	}
513: 
514: 	func(obj int) {
515: 		defer cfgCtlr.configQueue.Done(obj)
516: 		specificDelay, err := cfgCtlr.syncOne()
517: 		switch {
518: 		case err != nil:
519: 			klog.Error(err)
520: 			cfgCtlr.configQueue.AddRateLimited(obj)
521: 		case specificDelay > 0:
522: 			cfgCtlr.configQueue.AddAfter(obj, specificDelay)
523: 		default:
524: 			cfgCtlr.configQueue.Forget(obj)
525: 		}
526: 	}(obj)
527: 
528: 	return true
529: }
530: 
531: // syncOne does one full synchronization.  It reads all the API
532: // objects that configure API Priority and Fairness and updates the
533: // local configController accordingly.
534: // Only invoke this in the one and only worker goroutine
535: func (cfgCtlr *configController) syncOne() (specificDelay time.Duration, err error) {
536: 	klog.V(5).Infof("%s syncOne at %s", cfgCtlr.name, cfgCtlr.clock.Now().Format(timeFmt))
537: 	all := labels.Everything()
538: 	newPLs, err := cfgCtlr.plLister.List(all)
539: 	if err != nil {
540: 		return 0, fmt.Errorf("unable to list PriorityLevelConfiguration objects: %w", err)
541: 	}
542: 	newFSs, err := cfgCtlr.fsLister.List(all)
543: 	if err != nil {
544: 		return 0, fmt.Errorf("unable to list FlowSchema objects: %w", err)
545: 	}
546: 	return cfgCtlr.digestConfigObjects(newPLs, newFSs)
547: }
548: 
549: // cfgMeal is the data involved in the process of digesting the API
550: // objects that configure API Priority and Fairness.  All the config
551: // objects are digested together, because this is the simplest way to
552: // cope with the various dependencies between objects.  The process of
553: // digestion is done in four passes over config objects --- three
554: // passes over PriorityLevelConfigurations and one pass over the
555: // FlowSchemas --- with the work dvided among the passes according to
556: // those dependencies.
557: type cfgMeal struct {
558: 	cfgCtlr *configController
559: 
560: 	newPLStates map[string]*priorityLevelState
561: 
562: 	// The sum of the concurrency shares of the priority levels in the
563: 	// new configuration
564: 	shareSum float64
565: 
566: 	// These keep track of which mandatory priority level config
567: 	// objects have been digested
568: 	haveExemptPL, haveCatchAllPL bool
569: 
570: 	// Buffered FlowSchema status updates to do.  Do them when the
571: 	// lock is not held, to avoid a deadlock due to such a request
572: 	// provoking a call into this controller while the lock held
573: 	// waiting on that request to complete.
574: 	fsStatusUpdates []fsStatusUpdate
575: 
576: 	maxWaitingRequests, maxExecutingRequests int
577: }
578: 
579: // A buffered set of status updates for FlowSchemas
580: type fsStatusUpdate struct {
581: 	flowSchema *flowcontrol.FlowSchema
582: 	condition  flowcontrol.FlowSchemaCondition
583: 	oldValue   flowcontrol.FlowSchemaCondition
584: }
585: 
586: // digestConfigObjects is given all the API objects that configure
587: // cfgCtlr and writes its consequent new configState.
588: // Only invoke this in the one and only worker goroutine
589: func (cfgCtlr *configController) digestConfigObjects(newPLs []*flowcontrol.PriorityLevelConfiguration, newFSs []*flowcontrol.FlowSchema) (time.Duration, error) {
590: 	fsStatusUpdates := cfgCtlr.lockAndDigestConfigObjects(newPLs, newFSs)
591: 	var errs []error
592: 	currResult := updateAttempt{
593: 		timeUpdated:  cfgCtlr.clock.Now(),
594: 		updatedItems: sets.String{},
595: 	}
596: 	var suggestedDelay time.Duration
597: 	for _, fsu := range fsStatusUpdates {
598: 		// if we should skip this name, indicate we will need a delay, but continue with other entries
599: 		if cfgCtlr.shouldDelayUpdate(fsu.flowSchema.Name) {
600: 			if suggestedDelay == 0 {
601: 				suggestedDelay = time.Duration(30+rand.Intn(45)) * time.Second
602: 			}
603: 			continue
604: 		}
605: 
606: 		// if we are going to issue an update, be sure we track every name we update so we know if we update it too often.
607: 		currResult.updatedItems.Insert(fsu.flowSchema.Name)
608: 		if klogV := klog.V(4); klogV.Enabled() {
609: 			klogV.Infof("%s writing Condition %s to FlowSchema %s, which had ResourceVersion=%s, because its previous value was %s, diff: %s",
610: 				cfgCtlr.name, fsu.condition, fsu.flowSchema.Name, fsu.flowSchema.ResourceVersion, fcfmt.Fmt(fsu.oldValue), diff.Diff(fsu.oldValue, fsu.condition))
611: 		}
612: 
613: 		if err := apply(cfgCtlr.flowcontrolClient.FlowSchemas(), fsu, cfgCtlr.asFieldManager); err != nil {
614: 			if apierrors.IsNotFound(err) {
615: 				// This object has been deleted.  A notification is coming
616: 				// and nothing more needs to be done here.
617: 				klog.V(5).Infof("%s at %s: attempted update of concurrently deleted FlowSchema %s; nothing more needs to be done", cfgCtlr.name, cfgCtlr.clock.Now().Format(timeFmt), fsu.flowSchema.Name)
618: 			} else {
619: 				errs = append(errs, fmt.Errorf("failed to set a status.condition for FlowSchema %s: %w", fsu.flowSchema.Name, err))
620: 			}
621: 		}
622: 	}
623: 	cfgCtlr.addUpdateResult(currResult)
624: 
625: 	return suggestedDelay, utilerrors.NewAggregate(errs)
626: }
627: 
628: func apply(client flowcontrolclient.FlowSchemaInterface, fsu fsStatusUpdate, asFieldManager string) error {
629: 	applyOptions := metav1.ApplyOptions{FieldManager: asFieldManager, Force: true}
630: 
631: 	// the condition field in fsStatusUpdate holds the new condition we want to update.
632: 	// TODO: this will break when we have multiple conditions for a flowschema
633: 	_, err := client.ApplyStatus(context.TODO(), toFlowSchemaApplyConfiguration(fsu), applyOptions)
634: 	return err
635: }
636: 
637: func toFlowSchemaApplyConfiguration(fsUpdate fsStatusUpdate) *flowcontrolapplyconfiguration.FlowSchemaApplyConfiguration {
638: 	condition := flowcontrolapplyconfiguration.FlowSchemaCondition().
639: 		WithType(fsUpdate.condition.Type).
640: 		WithStatus(fsUpdate.condition.Status).
641: 		WithReason(fsUpdate.condition.Reason).
642: 		WithLastTransitionTime(fsUpdate.condition.LastTransitionTime).
643: 		WithMessage(fsUpdate.condition.Message)
644: 
645: 	return flowcontrolapplyconfiguration.FlowSchema(fsUpdate.flowSchema.Name).
646: 		WithStatus(flowcontrolapplyconfiguration.FlowSchemaStatus().
647: 			WithConditions(condition),
648: 		)
649: }
650: 
651: // shouldDelayUpdate checks to see if a flowschema has been updated too often and returns true if a delay is needed.
652: // Only invoke this in the one and only worker goroutine
653: func (cfgCtlr *configController) shouldDelayUpdate(flowSchemaName string) bool {
654: 	numUpdatesInPastMinute := 0
655: 	oneMinuteAgo := cfgCtlr.clock.Now().Add(-1 * time.Minute)
656: 	for idx, update := range cfgCtlr.mostRecentUpdates {
657: 		if oneMinuteAgo.After(update.timeUpdated) {
658: 			// this and the remaining items are no longer relevant
659: 			cfgCtlr.mostRecentUpdates = cfgCtlr.mostRecentUpdates[:idx]
660: 			return false
661: 		}
662: 		if update.updatedItems.Has(flowSchemaName) {
663: 			numUpdatesInPastMinute++
664: 			if numUpdatesInPastMinute > 5 {
665: 				return true
666: 			}
667: 		}
668: 	}
669: 	return false
670: }
671: 
672: // addUpdateResult adds the result. It isn't a ring buffer because
673: // this is small and rate limited.
674: // Only invoke this in the one and only worker goroutine
675: func (cfgCtlr *configController) addUpdateResult(result updateAttempt) {
676: 	cfgCtlr.mostRecentUpdates = append([]updateAttempt{result}, cfgCtlr.mostRecentUpdates...)
677: }
678: 
679: func (cfgCtlr *configController) lockAndDigestConfigObjects(newPLs []*flowcontrol.PriorityLevelConfiguration, newFSs []*flowcontrol.FlowSchema) []fsStatusUpdate {
680: 	cfgCtlr.lock.Lock()
681: 	defer cfgCtlr.lock.Unlock()
682: 	meal := cfgMeal{
683: 		cfgCtlr:     cfgCtlr,
684: 		newPLStates: make(map[string]*priorityLevelState),
685: 	}
686: 
687: 	meal.digestNewPLsLocked(newPLs)
688: 	meal.digestFlowSchemasLocked(newFSs)
689: 	meal.processOldPLsLocked()
690: 
691: 	// Supply missing mandatory PriorityLevelConfiguration objects
692: 	if !meal.haveExemptPL {
693: 		meal.imaginePL(fcboot.MandatoryPriorityLevelConfigurationExempt)
694: 	}
695: 	if !meal.haveCatchAllPL {
696: 		meal.imaginePL(fcboot.MandatoryPriorityLevelConfigurationCatchAll)
697: 	}
698: 
699: 	meal.finishQueueSetReconfigsLocked()
700: 
